import{_ as e,c as a,o as t,N as r}from"./chunks/framework.0799945b.js";const k=JSON.parse('{"title":"设计思路","description":"","frontmatter":{},"headers":[],"relativePath":"design.md","lastUpdated":1683817037000}'),i={name:"design.md"},o=r('<h1 id="设计思路" tabindex="-1">设计思路 <a class="header-anchor" href="#设计思路" aria-label="Permalink to &quot;设计思路&quot;">​</a></h1><h2 id="目标" tabindex="-1">目标 <a class="header-anchor" href="#目标" aria-label="Permalink to &quot;目标&quot;">​</a></h2><p>本项目目标是赋予 WireGuard 动态组网的能力，方便企业用户根据自身需求进行私有化部署或二次开发。 在网络层面属于Layer3.</p><h2 id="客户端与服务器端通信" tabindex="-1">客户端与服务器端通信 <a class="header-anchor" href="#客户端与服务器端通信" aria-label="Permalink to &quot;客户端与服务器端通信&quot;">​</a></h2><p><strong>密钥选择</strong> 使用 <code>Curve25519</code> 来做密钥协商（x25519）和签名验证 (ed25519)</p><p>参考 <a href="https://docs.rs/zerotier/latest/zerotier/" target="_blank" rel="noreferrer">ZeroTier</a> 的 key 生成方式。</p><p>PublicKey ：Concatenation of X25519 public key (first 32 bytes) and Ed25519 public key (last 32 bytes).</p><p>SecretKey ：Concatenation of X25519 static secret (first 32 bytes) and Ed25519 secret key (last 32 bytes).</p><p><strong>认证方式</strong>： 使用 ed25519 密钥对：</p><p>timestamp + networkId + nonce =&gt; plain text</p><p>Client: (encrypt(private key, plain text) =&gt; sign) + plain text + public key</p><p>Server: validate(public key, plain text)</p><p>客户端与服务器端通信分为两个阶段：</p><h3 id="客户端认证-登录" tabindex="-1">客户端认证/登录 <a class="header-anchor" href="#客户端认证-登录" aria-label="Permalink to &quot;客户端认证/登录&quot;">​</a></h3><ol><li>通过 gPRC 发送 OAuth2 + 认证方式, 若OAuth2 通过，则正常通信。</li><li>通过 gRPC 发送 认证方式，若客户端若不存在，则进入 Waiting 认证状态，若存在，则正常通信。 <s>2. 服务器端输出 WireGuard 配置，客户端导入后，可自行连接（支持原生 WireGuard）。</s></li></ol><h4 id="fornet-client" tabindex="-1">ForNet Client <a class="header-anchor" href="#fornet-client" aria-label="Permalink to &quot;ForNet Client&quot;">​</a></h4><ol><li>[客户端]检测当前机器有无配置，无配置则生成公私钥，将公钥传输给服务器端，获取配置，启动 WireGuard 客户端跑命令。</li><li>[服务器端]根据公钥匹配服务器端节点，有则下发配置，无则成为待连接点。由服务器端通过后，再下发配置到客户端。连接信息放入 ConnectionManager 和 Session Table.</li><li>[服务器端]通过 gRPC 检测客户端活性。</li></ol><h4 id="wip-wireguard-client-wrapper" tabindex="-1">[WIP] WireGuard Client Wrapper <a class="header-anchor" href="#wip-wireguard-client-wrapper" aria-label="Permalink to &quot;[WIP] WireGuard Client Wrapper&quot;">​</a></h4><ol><li>[客户端] 检测 WireGuard 状态，若ok，进入 ForNet Client【2】执行流程；若不 ok，则退出或使用 Rust WireGuard 版进行连接。</li></ol><h3 id="通信中" tabindex="-1">通信中 <a class="header-anchor" href="#通信中" aria-label="Permalink to &quot;通信中&quot;">​</a></h3><p>在通信中，服务器端与客户端建立额外的gRPC连接，服务器端通过连接下发指令：如：更新配置、更新网络拓扑、剔除下线等。</p><p>当客户端接收的配置变更版本与服务器端推送的不一致时，客户端可通过gRPC拉取最新配置。</p><h2 id="网络拓扑" tabindex="-1">网络拓扑 <a class="header-anchor" href="#网络拓扑" aria-label="Permalink to &quot;网络拓扑&quot;">​</a></h2><p>网络拓扑的设定方式：</p><p>目前暂时支持 中继，后续支持Ingress、Outgress、穿透。</p><h2 id="客户端创建方式" tabindex="-1">客户端创建方式 <a class="header-anchor" href="#客户端创建方式" aria-label="Permalink to &quot;客户端创建方式&quot;">​</a></h2><p>Web端展示激活码base64、二维码，或 SSO登录 base64、二维码</p><p>激活码格式: 1|endpoint|hashId(networkId)|?hashId(NodeId)|?NodeType NodeType 目前先不支持</p><p>SSO格式: 2|endpoint|hashId(networkId)|keycloakUrl|realm|clientId</p><h3 id="web端创建客户端" tabindex="-1">Web端创建客户端 <a class="header-anchor" href="#web端创建客户端" aria-label="Permalink to &quot;Web端创建客户端&quot;">​</a></h3><p>Web端创建并生成密钥，生成 激活码\\SSO base64、二维码。（节点页面放置）</p><h3 id="客户端直接加入" tabindex="-1">客户端直接加入 <a class="header-anchor" href="#客户端直接加入" aria-label="Permalink to &quot;客户端直接加入&quot;">​</a></h3><p>客户端通过扫二维码/命令行指令 + 激活码/GUI+粘贴激活码 加入网络。（网络详情页面放置）</p><h2 id="关键字段梳理" tabindex="-1">关键字段梳理 <a class="header-anchor" href="#关键字段梳理" aria-label="Permalink to &quot;关键字段梳理&quot;">​</a></h2><h3 id="节点-node" tabindex="-1">节点（Node） <a class="header-anchor" href="#节点-node" aria-label="Permalink to &quot;节点（Node）&quot;">​</a></h3><p>Node: name, ip, type</p><p>Client Node:</p><p>Relay Node: cidr</p>',38),n=[o];function l(d,s,p,h,c,u){return t(),a("div",null,n)}const f=e(i,[["render",l]]);export{k as __pageData,f as default};
